window.POM_QUESTION_BANK = {"topics": [{"id": "cellular-biology", "name": "Cellular Biology", "counts": {"sba": 40, "vsaq": 35, "saq": 25}}, {"id": "haematology", "name": "Haematology", "counts": {"sba": 40, "vsaq": 35, "saq": 25}}, {"id": "immunity", "name": "Immunity", "counts": {"sba": 40, "vsaq": 35, "saq": 25}}, {"id": "genetics", "name": "Genetics", "counts": {"sba": 40, "vsaq": 35, "saq": 25}}], "questions": {"cellular-biology": {"sba": [{"q": "Which reaction type describes the breakdown of larger molecules with release of energy stored as ATP?", "a": "Catabolic", "options": ["Catabolic", "Anabolic", "Isomerisation", "Ligation"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Where does glycolysis occur in a eukaryotic cell?", "a": "Cytosol", "options": ["Cytosol", "Mitochondrial matrix", "Inner mitochondrial membrane", "Rough ER"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "A patient develops lactic acidosis during severe hypoxia. Which metabolic need does lactate production primarily meet?", "a": "Regeneration of NAD+ so glycolysis can continue", "options": ["Regeneration of NAD+ so glycolysis can continue", "Direct production of 36 ATP per glucose", "Feeding acetyl-CoA into the TCA cycle", "Synthesis of NADPH for anabolism"], "lecture": "2.1 Cell Metabolism I", "level": "application", "explanation": "In hypoxia oxidative phosphorylation stops; converting pyruvate to lactate regenerates NAD+ for GAPDH (glycolysis step 6)."}, {"q": "Which coenzyme from the pentose phosphate pathway is especially important for protecting red cells from oxidative damage?", "a": "NADPH", "options": ["NADPH", "NADH", "FADH2", "Coenzyme A"], "lecture": "2.1 Cell Metabolism I", "level": "understanding"}, {"q": "Phosphofructokinase-1 is inhibited by high ATP. What does this illustrate?", "a": "Feedback inhibition of a committed glycolytic step when energy is plentiful", "options": ["Feedback inhibition of a committed glycolytic step when energy is plentiful", "Irreversible activation of glycogenolysis", "Allosteric activation of pyruvate dehydrogenase by ATP", "Competitive inhibition of hexokinase by glucose"], "lecture": "2.6 Integration of Metabolism", "level": "inference"}, {"q": "Creatine kinase catalyses reversible transfer of phosphate between creatine and ADP. When is the creatine phosphate store most useful?", "a": "Brief high-intensity muscle work when ATP demand spikes", "options": ["Brief high-intensity muscle work when ATP demand spikes", "Overnight fasting hepatic gluconeogenesis", "Long-term storage of fatty acids in adipose tissue", "DNA replication in S phase"], "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Statins inhibit HMG-CoA reductase. What is the direct metabolic consequence?", "a": "Reduced de novo cholesterol synthesis", "options": ["Reduced de novo cholesterol synthesis", "Increased bile acid conjugation only", "Blockade of fatty acid β-oxidation", "Inhibition of LDL receptor transcription only"], "lecture": "2.5 Cholesterol", "level": "application"}, {"q": "Which junctional complex forms a belt-like seal that limits paracellular diffusion between epithelial cells?", "a": "Tight junction (zonula occludens)", "options": ["Tight junction (zonula occludens)", "Gap junction", "Hemidesmosome", "Focal adhesion"], "lecture": "2.3 Epithelial Cells and Tissues", "level": "recall"}, {"q": "A tumour suppressor gene normally restrains the cell cycle. Loss of both alleles typically contributes to cancer via which mechanism?", "a": "Loss of a brake on proliferation / genomic integrity", "options": ["Loss of a brake on proliferation / genomic integrity", "Gain of a constitutively active growth signal", "Increased DNA repair fidelity only", "Enhanced contact inhibition"], "lecture": "2.15 Cancer", "level": "understanding"}, {"q": "During acute inflammation, which event best explains endothelial gaps and protein-rich exudate?", "a": "Increased vascular permeability", "options": ["Increased vascular permeability", "Decreased hydrostatic pressure only", "Complete thrombosis of all capillaries", "Immediate fibrosis of the interstitium"], "lecture": "2.13 Inflammation", "level": "understanding"}, {"q": "Apoptosis differs from necrosis mainly because apoptotic cell death is typically:", "a": "Programmed, energy-dependent, and non-inflammatory if orderly", "options": ["Programmed, energy-dependent, and non-inflammatory if orderly", "Always caused by trauma with membrane rupture and inflammation", "Identical to coagulative necrosis histologically", "Independent of caspase pathways"], "lecture": "2.11 Cell Fate and Injury", "level": "understanding"}, {"q": "A G-protein-coupled receptor activates Gs. What is the immediate next effect on adenylyl cyclase?", "a": "Increased cAMP production", "options": ["Increased cAMP production", "Cleavage of PIP2 to IP3 and DAG", "Opening of ligand-gated Na+ channels only", "Direct phosphorylation of tyrosine residues on the receptor"], "lecture": "2.10 Cell Signalling", "level": "recall"}, {"q": "In Michaelis–Menten kinetics, a competitive inhibitor typically:", "a": "Increases apparent Km without changing Vmax", "options": ["Increases apparent Km without changing Vmax", "Decreases Vmax without changing Km", "Increases both Km and Vmax equally", "Has no effect on the Lineweaver–Burk plot"], "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Which fluid compartment contains the largest volume of body water in a typical adult?", "a": "Intracellular fluid", "options": ["Intracellular fluid", "Interstitial fluid", "Plasma", "Transcellular fluid"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "recall"}, {"q": "A patient has hyponatraemia with low plasma osmolality. Water shifts tend to move:", "a": "Into cells, risking cellular swelling", "options": ["Into cells, risking cellular swelling", "Out of cells, causing crenation only", "Only into the plasma from interstitial fluid with no cell effect", "Only into bone mineral stores"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "application"}, {"q": "Collagen fibres in the extracellular matrix primarily provide:", "a": "Tensile strength", "options": ["Tensile strength", "Elastic recoil only", "Hormone storage only", "ATP generation"], "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "Which phase of the cell cycle is DNA replicated?", "a": "S phase", "options": ["S phase", "G0", "M phase cytokinesis only", "G1 checkpoint arrest only"], "lecture": "2.8 Cell Replication", "level": "recall"}, {"q": "Oncogenes are most accurately described as:", "a": "Mutated/activated versions of proto-oncogenes that drive proliferation", "options": ["Mutated/activated versions of proto-oncogenes that drive proliferation", "Genes that always prevent DNA replication", "Identical to tumour suppressor genes", "Only viral genes with no cellular counterparts"], "lecture": "2.15 Cancer", "level": "understanding"}, {"q": "A biopsy shows loss of normal tissue architecture with nuclear atypia and invasion through basement membrane. This best describes:", "a": "Malignant neoplasm", "options": ["Malignant neoplasm", "Hyperplasia only", "Metaplasia only", "Hypertrophy only"], "lecture": "2.16 Histopathology", "level": "application"}, {"q": "Which statement best links inflammation to tissue repair?", "a": "Inflammation clears injurious agents and sets the stage for healing, but chronic inflammation can drive fibrosis", "options": ["Inflammation clears injurious agents and sets the stage for healing, but chronic inflammation can drive fibrosis", "Inflammation always regenerates tissue without scarring", "Repair never involves angiogenesis", "Neutrophils alone produce collagen for scar formation"], "lecture": "2.13 Inflammation", "level": "inference"}, {"q": "Which enzyme catalyses the committed step of glycolysis most often cited as the key control point?", "a": "Phosphofructokinase-1", "options": ["Phosphofructokinase-1", "Aldolase", "Enolase", "Phosphoglycerate mutase"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Oxidative phosphorylation occurs primarily at which mitochondrial location?", "a": "Inner mitochondrial membrane", "options": ["Inner mitochondrial membrane", "Cytosol", "Outer membrane only", "Golgi lumen"], "lecture": "2.2 Cell Metabolism II", "level": "recall"}, {"q": "Uncoupling of oxidative phosphorylation typically increases heat production because:", "a": "Proton gradient energy is dissipated as heat rather than making ATP", "options": ["Proton gradient energy is dissipated as heat rather than making ATP", "Glycolysis stops completely", "DNA replication accelerates", "LDL receptors are upregulated"], "lecture": "2.2 Cell Metabolism II", "level": "understanding"}, {"q": "Which epithelial specialisation increases apical surface area for absorption?", "a": "Microvilli", "options": ["Microvilli", "Cilia only for absorption", "Desmosomes", "Gap junctions"], "lecture": "2.3 Epithelial Cells and Tissues", "level": "recall"}, {"q": "Desmosomes primarily provide:", "a": "Strong cell–cell adhesion resisting mechanical stress", "options": ["Strong cell–cell adhesion resisting mechanical stress", "Sealing of the paracellular pathway only", "ATP synthesis", "Hormone secretion only"], "lecture": "2.3 Epithelial Cells and Tissues", "level": "understanding"}, {"q": "Raised plasma creatine kinase after crush injury most directly indicates:", "a": "Skeletal muscle damage with enzyme leakage into blood", "options": ["Skeletal muscle damage with enzyme leakage into blood", "Hepatic gluconeogenesis only", "Iron deficiency anaemia", "Vitamin K deficiency"], "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Cholesterol is a precursor for which of the following?", "a": "Steroid hormones and bile acids", "options": ["Steroid hormones and bile acids", "Only glycogen", "Only haemoglobin", "Only peptidoglycan"], "lecture": "2.5 Cholesterol", "level": "recall"}, {"q": "In the fed state, which pathway is favoured in hepatocytes?", "a": "Glycogen synthesis and fatty acid synthesis", "options": ["Glycogen synthesis and fatty acid synthesis", "Ketogenesis as the main pathway", "Only proteolysis", "Only gluconeogenesis"], "lecture": "2.6 Integration of Metabolism", "level": "application"}, {"q": "Which membrane lipid contributes most to bilayer fluidity regulation with cholesterol?", "a": "Phospholipids with varying fatty acid saturation", "options": ["Phospholipids with varying fatty acid saturation", "Peptidoglycan", "DNA", "Glycogen"], "lecture": "2.7 Cell Integrity", "level": "understanding"}, {"q": "The G1/S checkpoint primarily ensures:", "a": "Adequate conditions and integrity before DNA replication", "options": ["Adequate conditions and integrity before DNA replication", "Chromosome segregation only", "Cytokinesis completion only", "Only mitochondrial fission"], "lecture": "2.8 Cell Replication", "level": "understanding"}, {"q": "Matrix metalloproteinases (MMPs) are important in tissue remodelling because they:", "a": "Degrade extracellular matrix components", "options": ["Degrade extracellular matrix components", "Synthesise ATP in mitochondria", "Replicate DNA", "Bind oxygen in red cells"], "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "Receptor tyrosine kinases typically signal by:", "a": "Autophosphorylation and recruitment of SH2-domain proteins", "options": ["Autophosphorylation and recruitment of SH2-domain proteins", "Only opening chloride channels", "Only producing antibodies", "Only activating complement C1"], "lecture": "2.10 Cell Signalling", "level": "understanding"}, {"q": "Reversible cell injury is most consistent with which finding?", "a": "Cellular swelling that can resolve if the insult is removed", "options": ["Cellular swelling that can resolve if the insult is removed", "Nuclear karyorrhexis with irreversible membrane rupture always", "Complete loss of all nuclei with scarring already present", "Metastatic deposits"], "lecture": "2.11 Cell Fate and Injury", "level": "application"}, {"q": "Hypertrophy differs from hyperplasia because hypertrophy is:", "a": "Increase in cell size without necessarily increasing cell number", "options": ["Increase in cell size without necessarily increasing cell number", "Increase in cell number only", "Change from one differentiated cell type to another", "Disordered growth with invasion"], "lecture": "2.11 Cell Fate and Injury", "level": "understanding"}, {"q": "Metaplasia is best defined as:", "a": "Replacement of one differentiated cell type by another", "options": ["Replacement of one differentiated cell type by another", "Increase in cell size only", "Malignant invasion", "Programmed cell death"], "lecture": "2.11 Cell Fate and Injury", "level": "recall"}, {"q": "Which mediator is a classic acute-phase reactant used clinically as an inflammation marker?", "a": "C-reactive protein (CRP)", "options": ["C-reactive protein (CRP)", "Albumin rising in inflammation", "LDL cholesterol", "HbA1c"], "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "A non-competitive inhibitor on a Lineweaver–Burk plot typically:", "a": "Decreases Vmax with Km unchanged", "options": ["Decreases Vmax with Km unchanged", "Increases Vmax only", "Increases Km with Vmax unchanged", "Has identical lines to uninhibited enzyme"], "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Hallmarks of cancer include sustained proliferative signalling and:", "a": "Evasion of growth suppressors and enabling replicative immortality", "options": ["Evasion of growth suppressors and enabling replicative immortality", "Obligate apoptosis of all tumour cells", "Complete contact inhibition always", "Inability to induce angiogenesis"], "lecture": "2.15 Cancer", "level": "recall"}, {"q": "Coagulative necrosis is classically associated with:", "a": "Ischaemic infarction in solid organs (e.g. heart, kidney)", "options": ["Ischaemic infarction in solid organs (e.g. heart, kidney)", "Only abscess formation in brain", "Only caseating granulomas always", "Apoptotic bodies only"], "lecture": "2.16 Histopathology", "level": "application"}, {"q": "If a cell cannot regenerate NAD+ and oxygen is absent, which process fails first to sustain ATP?", "a": "Continued glycolytic flux after NADH accumulates", "options": ["Continued glycolytic flux after NADH accumulates", "DNA transcription of albumin", "LDL receptor endocytosis only", "Collagen cross-linking only"], "lecture": "2.1 Cell Metabolism I", "level": "inference"}], "vsaq": [{"q": "Name the cytosolic pathway that converts glucose to pyruvate.", "a": "Glycolysis", "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Which enzyme phosphorylates glucose in most tissues?", "a": "Hexokinase", "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "How many net ATP are produced from anaerobic glycolysis per glucose?", "a": "2", "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Name the mitochondrial cycle that oxidises acetyl-CoA.", "a": ["TCA cycle", "Krebs cycle", "Citric acid cycle"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Which organelle houses oxidative phosphorylation?", "a": "Mitochondria", "lecture": "2.2 Cell Metabolism II", "level": "recall"}, {"q": "Statins inhibit which rate-limiting enzyme of cholesterol synthesis?", "a": "HMG-CoA reductase", "lecture": "2.5 Cholesterol", "level": "recall"}, {"q": "Name the main plasma lipoprotein that delivers cholesterol to tissues via LDL receptors.", "a": "LDL", "lecture": "2.5 Cholesterol", "level": "recall"}, {"q": "Which kinase buffers ATP using creatine phosphate?", "a": "Creatine kinase", "lecture": "2.4 Creatine Kinase", "level": "recall"}, {"q": "Name the programmed form of cell death involving caspases.", "a": "Apoptosis", "lecture": "2.11 Cell Fate and Injury", "level": "recall"}, {"q": "Which cell-cycle phase follows G1?", "a": "S phase", "lecture": "2.8 Cell Replication", "level": "recall"}, {"q": "Name the second messenger produced by adenylyl cyclase.", "a": "cAMP", "lecture": "2.10 Cell Signalling", "level": "recall"}, {"q": "What is the most abundant cation in intracellular fluid?", "a": ["K+", "Potassium"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "recall"}, {"q": "Name the cardinal feature of inflammation meaning redness.", "a": "Rubor", "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "A competitive inhibitor increases which Michaelis–Menten parameter?", "a": "Km", "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Name a classic tumour suppressor gene mutated in many cancers.", "a": ["p53", "TP53"], "lecture": "2.15 Cancer", "level": "recall"}, {"q": "Which ECM protein provides tensile strength?", "a": "Collagen", "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "Tight junctions primarily limit which transport route?", "a": "Paracellular", "lecture": "2.3 Epithelial Cells and Tissues", "level": "understanding"}, {"q": "NADPH is generated mainly by which pathway?", "a": ["Pentose phosphate pathway", "PPP", "HMP shunt"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Name the enzyme converting pyruvate to lactate.", "a": ["Lactate dehydrogenase", "LDH"], "lecture": "2.1 Cell Metabolism I", "level": "recall"}, {"q": "Final electron acceptor in oxidative phosphorylation?", "a": "Oxygen", "lecture": "2.2 Cell Metabolism II", "level": "recall"}, {"q": "Name the epithelial junction allowing ion passage between cells.", "a": "Gap junction", "lecture": "2.3 Epithelial Cells and Tissues", "level": "recall"}, {"q": "CK-MB isoform elevation classically suggests injury to?", "a": ["Heart", "Myocardium", "Cardiac muscle"], "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Bile acids are synthesised from which lipid?", "a": "Cholesterol", "lecture": "2.5 Cholesterol", "level": "recall"}, {"q": "In fasting, hepatocytes produce glucose via?", "a": "Gluconeogenesis", "lecture": "2.6 Integration of Metabolism", "level": "recall"}, {"q": "Name programmed necrosis-like inflammatory death sometimes contrasted with apoptosis.", "a": "Necroptosis", "lecture": "2.11 Cell Fate and Injury", "level": "recall"}, {"q": "Cell-cycle phase of mitosis?", "a": "M phase", "lecture": "2.8 Cell Replication", "level": "recall"}, {"q": "Main structural glycoprotein linking cells to ECM?", "a": ["Integrins", "Fibronectin"], "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "IP3 releases which ion from ER stores?", "a": ["Ca2+", "Calcium"], "lecture": "2.10 Cell Signalling", "level": "recall"}, {"q": "Cardinal sign of inflammation meaning swelling?", "a": "Tumor", "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "Km is substrate concentration at what fraction of Vmax?", "a": "Half", "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Angiogenesis means formation of?", "a": "New vessels", "lecture": "2.15 Cancer", "level": "recall"}, {"q": "Caseating necrosis is classic in which infection type?", "a": ["TB", "Tuberculosis"], "lecture": "2.16 Histopathology", "level": "recall"}, {"q": "Na+/K+ ATPase pumps how many Na+ out per cycle?", "a": "3", "lecture": "2.12 Fluid Compartments and Solutes", "level": "recall"}, {"q": "Most abundant extracellular cation?", "a": ["Na+", "Sodium"], "lecture": "2.12 Fluid Compartments and Solutes", "level": "recall"}, {"q": "Name the process converting one adult cell type to another.", "a": "Metaplasia", "lecture": "2.11 Cell Fate and Injury", "level": "recall"}], "saq": [{"q": "Explain why glycolysis can continue under anaerobic conditions while the TCA cycle and oxidative phosphorylation cannot, and state the key molecule regenerated by lactate dehydrogenase.", "a": "Without oxygen, the electron transport chain stops so NADH cannot be reoxidised there and the TCA cycle slows. Glycolysis can still yield net ATP if NAD+ is regenerated; LDH reduces pyruvate to lactate, oxidising NADH to NAD+, which allows GAPDH to keep working.", "lecture": "2.1 Cell Metabolism I", "level": "understanding"}, {"q": "Compare catabolic and anabolic pathways with respect to energy and molecular size, giving one example of each.", "a": "Catabolic pathways break larger molecules into smaller ones and typically release energy (e.g. glycolysis, β-oxidation). Anabolic pathways build larger molecules from smaller precursors and require energy input from ATP/NADPH (e.g. glycogen synthesis, fatty acid synthesis).", "lecture": "2.1 Cell Metabolism I", "level": "understanding"}, {"q": "A patient on a statin asks how the drug lowers LDL cholesterol. Outline the mechanism linking HMG-CoA reductase inhibition to increased hepatic LDL clearance.", "a": "Statins inhibit HMG-CoA reductase, reducing hepatocyte cholesterol synthesis. Lower intracellular cholesterol upregulates LDL receptor expression, increasing hepatic uptake of circulating LDL and thereby lowering plasma LDL.", "lecture": "2.5 Cholesterol", "level": "application"}, {"q": "Describe how creatine phosphate supports short bursts of intense muscle activity.", "a": "Muscle stores creatine phosphate. Creatine kinase transfers the phosphate to ADP to regenerate ATP rapidly when demand suddenly rises, bridging the gap until glycolysis and oxidative metabolism catch up.", "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Distinguish apoptosis from necrosis in terms of mechanism, morphology, and inflammatory consequence.", "a": "Apoptosis is programmed, ATP-dependent, involves caspase cascades, cell shrinkage and apoptotic bodies, and is usually non-inflammatory when cleared by phagocytes. Necrosis is accidental cell death from severe injury, with membrane rupture, cellular swelling, and typically provokes inflammation.", "lecture": "2.11 Cell Fate and Injury", "level": "understanding"}, {"q": "Outline the sequence of vascular events in acute inflammation and how they produce the cardinal signs.", "a": "Transient vasoconstriction may occur, then arteriolar vasodilation increases blood flow (rubor, calor). Increased permeability allows protein-rich exudate into tissues (tumor). Chemical mediators and pressure contribute to dolor; loss of function may follow.", "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "Explain how a gain-of-function mutation in a proto-oncogene differs from loss of a tumour suppressor in driving cancer.", "a": "Proto-oncogene activation (e.g. constitutively active growth signalling) acts in a dominant fashion—one allele can drive proliferation. Tumour suppressors normally restrain growth or protect the genome; typically both alleles must be lost (two-hit) for full effect.", "lecture": "2.15 Cancer", "level": "inference"}, {"q": "A GPCR coupled to Gs is activated by ligand. Trace the pathway from receptor to a typical cellular response involving protein kinase A.", "a": "Ligand-bound receptor activates Gs, which stimulates adenylyl cyclase to make cAMP. cAMP activates protein kinase A, which phosphorylates target proteins, altering enzyme activity or gene transcription depending on the cell type.", "lecture": "2.10 Cell Signalling", "level": "application"}, {"q": "Using Starling principles, explain how hypoalbuminaemia can cause oedema.", "a": "Plasma albumin is a major contributor to colloid osmotic (oncotic) pressure that retains fluid in capillaries. Low albumin reduces oncotic pressure, so net filtration increases and fluid accumulates in the interstitium as oedema.", "lecture": "2.12 Fluid Compartments and Solutes", "level": "application"}, {"q": "Describe how competitive and non-competitive inhibition differ on a Lineweaver–Burk plot.", "a": "Competitive inhibition increases apparent Km (x-intercept changes) but Vmax is unchanged (same y-intercept). Non-competitive inhibition decreases Vmax (y-intercept rises) while Km is typically unchanged.", "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Explain why epithelial polarity and tight junctions matter for barrier function in gut or kidney tubules.", "a": "Polarised epithelia have distinct apical and basolateral domains with different transporters. Tight junctions seal the paracellular route, forcing selective transcellular transport and maintaining gradients and barrier integrity.", "lecture": "2.3 Epithelial Cells and Tissues", "level": "inference"}, {"q": "Outline the roles of collagen and elastin in the extracellular matrix and give one tissue example for each.", "a": "Collagen provides tensile strength (e.g. tendon, dermis). Elastin provides elastic recoil (e.g. large arteries, lung). Together they determine mechanical properties of connective tissues.", "lecture": "2.9 Extracellular Matrix", "level": "recall"}, {"q": "Explain how the electron transport chain creates the proton-motive force used for ATP synthesis.", "a": "Complexes I, III and IV pump protons out as electrons flow to oxygen, creating an electrochemical gradient across the inner membrane. ATP synthase lets protons return, coupling that flow to phosphorylation of ADP.", "lecture": "2.2 Cell Metabolism II", "level": "understanding"}, {"q": "Compare tight junctions, adherens junctions and desmosomes in epithelia.", "a": "Tight junctions seal paracellular spaces and maintain polarity. Adherens junctions link actin cytoskeletons via cadherins. Desmosomes provide strong spot adhesions via intermediate filaments, resisting shear.", "lecture": "2.3 Epithelial Cells and Tissues", "level": "understanding"}, {"q": "Why might serum CK be a useful but non-specific marker of tissue injury?", "a": "CK leaks from damaged muscle (and some other tissues) into blood, so rises indicate injury. Isoenzymes (e.g. CK-MB) improve specificity, but many causes of muscle damage elevate total CK, so clinical context matters.", "lecture": "2.4 Creatine Kinase", "level": "application"}, {"q": "Outline how insulin and glucagon reciprocally regulate hepatic metabolism in fed versus fasting states.", "a": "Insulin promotes glycolysis, glycogen synthesis and lipogenesis while suppressing gluconeogenesis. Glucagon (fasting) raises cAMP, promoting glycogenolysis and gluconeogenesis and reducing opposing pathways.", "lecture": "2.6 Integration of Metabolism", "level": "application"}, {"q": "Describe how loss of cell-cycle checkpoints can contribute to genomic instability in cancer.", "a": "Checkpoints normally halt progression if DNA is damaged or conditions are unfit. Checkpoint failure allows replication/segregation of damaged genomes, accumulating mutations that drive tumour progression.", "lecture": "2.8 Cell Replication", "level": "inference"}, {"q": "Explain the role of integrins in cell–ECM adhesion and signalling.", "a": "Integrins bind ECM ligands (e.g. fibronectin, collagen) and link to the cytoskeleton. They transmit mechanical and chemical signals regulating survival, migration and differentiation (outside-in and inside-out signalling).", "lecture": "2.9 Extracellular Matrix", "level": "understanding"}, {"q": "A patient has irreversible cell injury after prolonged ischaemia. What cellular events distinguish this from reversible injury?", "a": "Reversible injury shows swelling and fatty change that can recover. Irreversible injury features severe membrane damage, mitochondrial dysfunction with dense deposits, calcium influx, and nuclear changes (pyknosis, karyorrhexis, karyolysis) leading to necrosis.", "lecture": "2.11 Cell Fate and Injury", "level": "application"}, {"q": "Outline the leukocyte extravasation cascade in acute inflammation.", "a": "Margination and rolling (selectins), firm adhesion (integrins), and transmigration (diapedesis) across endothelium, guided by chemokines, allowing neutrophils to reach the injured site.", "lecture": "2.13 Inflammation", "level": "recall"}, {"q": "Explain why Vmax reflects enzyme concentration while Km reflects affinity (approximately).", "a": "Vmax is reached when enzyme is saturated; more enzyme molecules raise Vmax. Km is the substrate concentration at half Vmax and is characteristic of the enzyme–substrate interaction (lower Km ≈ higher affinity), independent of enzyme amount in simple MM kinetics.", "lecture": "2.14 Enzyme Kinetics", "level": "understanding"}, {"q": "Using the Hallmarks of Cancer framework, explain how tumours can evade apoptosis.", "a": "Tumours may upregulate anti-apoptotic proteins (e.g. Bcl-2), lose pro-apoptotic factors/p53 function, or alter death-receptor signalling, allowing survival despite stress or DNA damage that would normally trigger programmed death.", "lecture": "2.15 Cancer", "level": "inference"}, {"q": "Differentiate hyperplasia, hypertrophy, atrophy and metaplasia with one example each.", "a": "Hyperplasia: increased cell number (e.g. lactating breast). Hypertrophy: increased cell size (e.g. cardiac myocytes in hypertension). Atrophy: decreased size/number (e.g. disuse muscle). Metaplasia: cell-type switch (e.g. squamous metaplasia in bronchi of smokers).", "lecture": "2.11 Cell Fate and Injury", "level": "recall"}, {"q": "How does chronic inflammation promote fibrosis, and why can that impair organ function?", "a": "Persistent inflammation sustains cytokine and growth-factor signalling that activates fibroblasts to deposit collagen. Excessive ECM stiffens and distorts tissue architecture, reducing specialised function (e.g. cirrhosis, pulmonary fibrosis).", "lecture": "2.13 Inflammation", "level": "inference"}, {"q": "Explain Starling forces across a capillary and what net filtration depends on.", "a": "Hydrostatic pressure drives filtration out; plasma oncotic pressure opposes it. Net filtration is the balance of hydrostatic and oncotic pressures (and lymphatic drainage clears excess interstitial fluid).", "lecture": "2.12 Fluid Compartments and Solutes", "level": "understanding"}]}, "haematology": {"sba": [{"q": "What is the approximate lifespan of a normal circulating erythrocyte?", "a": "120 days", "options": ["120 days", "10 days", "1 year", "24 hours"], "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Haemoglobin’s oxygen-binding curve is sigmoidal mainly because of:", "a": "Cooperative binding between haemoglobin subunits", "options": ["Cooperative binding between haemoglobin subunits", "Irreversible covalent binding of O2 to iron", "Only plasma dissolved oxygen", "Absence of allosteric effectors"], "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "A right shift of the oxygen dissociation curve (increased P50) means haemoglobin has:", "a": "Lower affinity for oxygen, facilitating unloading in tissues", "options": ["Lower affinity for oxygen, facilitating unloading in tissues", "Higher affinity, impairing tissue unloading", "No change in affinity", "Inability to bind CO2"], "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "Mean corpuscular volume (MCV) is low in which class of anaemia?", "a": "Microcytic anaemia", "options": ["Microcytic anaemia", "Macrocytic anaemia", "Normocytic anaemia only", "Haemolytic anaemia only"], "lecture": "3.3 Red Blood Cell Parameters", "level": "recall"}, {"q": "A patient has microcytic hypochromic anaemia. Which diagnosis is most consistent as a common cause?", "a": "Iron deficiency", "options": ["Iron deficiency", "Vitamin B12 deficiency", "Folate deficiency", "Acute blood loss with normal iron stores only"], "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Neutrophilia with left shift is most suggestive of:", "a": "Acute bacterial infection", "options": ["Acute bacterial infection", "Chronic parasitic infection only", "Immediate type I hypersensitivity alone", "Vitamin B12 deficiency alone"], "lecture": "3.5 White Blood Cells", "level": "application"}, {"q": "Eosinophilia is classically associated with:", "a": "Parasitic infection or allergy", "options": ["Parasitic infection or allergy", "Only acute pyogenic bacterial infection", "Only iron deficiency", "Only thrombocytopenia"], "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "On a blood film, schistocytes (fragmented red cells) raise concern for:", "a": "Microangiopathic haemolysis", "options": ["Microangiopathic haemolysis", "Iron deficiency alone", "Hypothyroidism alone", "Vitamin C deficiency alone"], "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "application"}, {"q": "Primary haemostasis mainly involves:", "a": "Platelet adhesion and aggregation forming a platelet plug", "options": ["Platelet adhesion and aggregation forming a platelet plug", "Only the extrinsic coagulation cascade generating fibrin", "Only fibrinolysis by plasmin", "Only complement activation"], "lecture": "3.8 Haemostasis", "level": "understanding"}, {"q": "Vitamin K is required for γ-carboxylation of which clotting factors?", "a": "II, VII, IX and X (and proteins C/S)", "options": ["II, VII, IX and X (and proteins C/S)", "Only factor VIII and vWF", "Only fibrinogen", "Only factor XIII"], "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Warfarin inhibits vitamin K–dependent clotting factor synthesis. Which laboratory test is used to monitor warfarin therapy?", "a": "INR / prothrombin time", "options": ["INR / prothrombin time", "APTT alone", "Bleeding time alone", "ESR alone"], "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "A patient of blood group A has which naturally occurring antibodies?", "a": "Anti-B", "options": ["Anti-B", "Anti-A", "Anti-A and anti-B", "Anti-D only"], "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Which ABO type is the universal red-cell donor in emergencies (packed red cells)?", "a": "O", "options": ["O", "AB", "A", "B"], "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Plasma is best defined as:", "a": "The liquid component of blood containing clotting factors", "options": ["The liquid component of blood containing clotting factors", "Plasma minus clotting factors (serum definition reversed)", "Only the cellular buffy coat", "Only haemoglobin solution"], "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Serum differs from plasma because serum lacks:", "a": "Clotting factors consumed in clot formation", "options": ["Clotting factors consumed in clot formation", "All proteins", "Electrolytes", "Water"], "lecture": "3.10 Plasma", "level": "understanding"}, {"q": "Low haptoglobin with raised bilirubin and LDH supports which process?", "a": "Haemolysis", "options": ["Haemolysis", "Iron deficiency without haemolysis", "Dehydration only", "Polycythaemia vera only"], "lecture": "3.10 Plasma", "level": "inference"}, {"q": "Landsteiner’s law states that:", "a": "People make antibodies to ABO antigens they lack on their own RBCs", "options": ["People make antibodies to ABO antigens they lack on their own RBCs", "Everyone has anti-A and anti-B regardless of group", "Rh antibodies are always naturally occurring at birth", "Platelets determine ABO type"], "lecture": "3.9 Blood Transfusion", "level": "understanding"}, {"q": "Haemophilia A is due to deficiency of:", "a": "Factor VIII", "options": ["Factor VIII", "Factor IX", "Factor VII", "von Willebrand factor only"], "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "A raised MCV with hypersegmented neutrophils suggests which deficiency?", "a": "B12 or folate deficiency", "options": ["B12 or folate deficiency", "Iron deficiency", "Acute blood loss only", "G6PD deficiency only"], "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Which cell lineage produces platelets?", "a": "Megakaryocytes", "options": ["Megakaryocytes", "Erythroblasts only", "Myeloblasts only", "Plasma cells"], "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Erythropoietin is produced mainly in the:", "a": "Kidney", "options": ["Kidney", "Spleen only", "Thymus only", "Gallbladder"], "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Reticulocytosis after acute blood loss indicates:", "a": "Marrow responding with increased red-cell production", "options": ["Marrow responding with increased red-cell production", "Iron stores are always normal", "Vitamin K deficiency", "Failure of erythropoiesis"], "lecture": "3.1 Red Blood Cells", "level": "application"}, {"q": "A left shift of the oxygen dissociation curve means:", "a": "Higher O2 affinity and less unloading at tissues", "options": ["Higher O2 affinity and less unloading at tissues", "Lower O2 affinity and more unloading", "No change in P50", "Inability to bind CO"], "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "2,3-BPG in red cells typically:", "a": "Decreases haemoglobin’s affinity for oxygen (right shift)", "options": ["Decreases haemoglobin’s affinity for oxygen (right shift)", "Increases affinity (left shift)", "Destroys haem groups", "Converts Hb to IgG"], "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "RDW is most useful because it reflects:", "a": "Variation in red-cell size (anisocytosis)", "options": ["Variation in red-cell size (anisocytosis)", "White-cell nuclear segmentation only", "Platelet granulation only", "Plasma viscosity only"], "lecture": "3.3 Red Blood Cell Parameters", "level": "recall"}, {"q": "Macrocytic anaemia with neurological signs is most concerning for:", "a": "Vitamin B12 deficiency", "options": ["Vitamin B12 deficiency", "Iron deficiency alone", "Acute haemorrhage alone", "Thalassaemia trait alone"], "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Basophilia is uncommon but may be seen in:", "a": "Myeloproliferative disorders (among other causes)", "options": ["Myeloproliferative disorders (among other causes)", "Iron deficiency as the classic sole cause", "Only viral upper respiratory infection always", "Only dehydration"], "lecture": "3.5 White Blood Cells", "level": "application"}, {"q": "Lymphocytosis is often associated with:", "a": "Viral infection", "options": ["Viral infection", "Only acute pyogenic abscess always", "Only iron deficiency", "Only haemophilia"], "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "Target cells on a blood film may be seen in:", "a": "Liver disease or haemoglobinopathies (among causes)", "options": ["Liver disease or haemoglobinopathies (among causes)", "Only acute bacterial meningitis always", "Only vitamin C deficiency", "Only thrombocytopenia"], "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "application"}, {"q": "von Willebrand factor is essential for:", "a": "Platelet adhesion to exposed subendothelium", "options": ["Platelet adhesion to exposed subendothelium", "Vitamin K synthesis", "Oxygen transport", "Complement alternative pathway initiation only"], "lecture": "3.8 Haemostasis", "level": "understanding"}, {"q": "APTT predominantly assesses which pathway components?", "a": "Intrinsic pathway (and common pathway)", "options": ["Intrinsic pathway (and common pathway)", "Only extrinsic tissue factor pathway exclusively", "Only fibrinolysis", "Only platelet aggregation"], "lecture": "3.8 Haemostasis", "level": "understanding"}, {"q": "Heparin therapy is typically monitored with:", "a": "APTT (for unfractionated heparin)", "options": ["APTT (for unfractionated heparin)", "INR only", "Bleeding time only", "HbA1c"], "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "Fresh frozen plasma is used clinically to:", "a": "Replace clotting factors", "options": ["Replace clotting factors", "Raise haematocrit like packed red cells", "Treat iron deficiency alone", "Replace only platelets"], "lecture": "3.9 Blood Transfusion", "level": "application"}, {"q": "Acute haemolytic transfusion reaction is most often due to:", "a": "ABO incompatibility", "options": ["ABO incompatibility", "Mild allergic urticaria only", "Citrate toxicity only", "Iron overload only"], "lecture": "3.9 Blood Transfusion", "level": "application"}, {"q": "D-dimer elevation suggests:", "a": "Fibrin formation and degradation (thrombosis/fibrinolysis activity)", "options": ["Fibrin formation and degradation (thrombosis/fibrinolysis activity)", "Iron deficiency specifically", "Only vitamin B12 deficiency", "Always a normal finding in health"], "lecture": "3.8 Haemostasis", "level": "understanding"}, {"q": "Thrombocytopenia increases risk of:", "a": "Mucocutaneous bleeding", "options": ["Mucocutaneous bleeding", "Only deep venous thrombosis always", "Only hypertension", "Only hyperviscosity"], "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "Ferritin is best interpreted as:", "a": "An iron-storage protein that also rises as an acute-phase reactant", "options": ["An iron-storage protein that also rises as an acute-phase reactant", "A clotting factor", "A white-cell chemokine only", "A haemoglobin isoform"], "lecture": "3.10 Plasma", "level": "understanding"}, {"q": "Hypersegmented neutrophils on film suggest:", "a": "Megaloblastic anaemia (B12/folate deficiency)", "options": ["Megaloblastic anaemia (B12/folate deficiency)", "Iron deficiency as the classic sole cause", "Acute blood loss only", "Dehydration only"], "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "application"}, {"q": "Sickle cell disease pathophysiology centres on:", "a": "Polymerisation of deoxygenated HbS distorting red cells", "options": ["Polymerisation of deoxygenated HbS distorting red cells", "Factor VIII deficiency", "IgE-mediated mast cell degranulation", "Trisomy 21"], "lecture": "3.7 Tales from the Haematology Clinic II", "level": "understanding"}, {"q": "If plasma oncotic pressure falls while hydrostatic pressure is unchanged, net capillary filtration tends to:", "a": "Increase, favouring oedema", "options": ["Increase, favouring oedema", "Decrease, preventing any interstitial fluid", "Stop lymphatic flow completely", "Raise haemoglobin affinity for O2 only"], "lecture": "3.10 Plasma", "level": "inference"}], "vsaq": [{"q": "Approximate lifespan of a normal RBC?", "a": "120 days", "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Name the oxygen-carrying protein in erythrocytes.", "a": "Haemoglobin", "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "What does a low MCV indicate?", "a": "Microcytosis", "lecture": "3.3 Red Blood Cell Parameters", "level": "understanding"}, {"q": "Name the most common cause of microcytic anaemia worldwide.", "a": "Iron deficiency", "lecture": "3.4 Tales from the Haematology Clinic I", "level": "recall"}, {"q": "Which white cell is most numerous in normal peripheral blood?", "a": "Neutrophil", "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "Name the fragmented red cells seen in microangiopathic haemolysis.", "a": "Schistocytes", "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "recall"}, {"q": "Primary haemostasis centres on which blood element?", "a": "Platelets", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Warfarin monitoring uses which standardised ratio?", "a": "INR", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Vitamin K–dependent factors include II, VII, IX and which other?", "a": "X", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Haemophilia A: which factor is deficient?", "a": ["Factor VIII", "VIII"], "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Universal red-cell donor ABO group?", "a": "O", "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Universal plasma donor ABO group?", "a": "AB", "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Plasma minus clotting factors equals?", "a": "Serum", "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Most abundant plasma protein?", "a": "Albumin", "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Name the iron-transport protein in plasma.", "a": "Transferrin", "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Low haptoglobin suggests what process?", "a": "Haemolysis", "lecture": "3.10 Plasma", "level": "inference"}, {"q": "P50 reflects haemoglobin’s affinity for which gas?", "a": "Oxygen", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "Name the pluripotent stem cells giving rise to blood lineages.", "a": ["HSCs", "Haemopoietic stem cells", "Hematopoietic stem cells"], "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Hormone stimulating red-cell production?", "a": "Erythropoietin", "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "Immature red cells with residual RNA in blood?", "a": "Reticulocytes", "lecture": "3.1 Red Blood Cells", "level": "recall"}, {"q": "A left-shifted ODC indicates what change in affinity?", "a": "Increased", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "Normal adult haemoglobin is mainly which type?", "a": "HbA", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "recall"}, {"q": "MCHC stands for mean corpuscular haemoglobin?", "a": "Concentration", "lecture": "3.3 Red Blood Cell Parameters", "level": "recall"}, {"q": "Macrocytosis means high?", "a": "MCV", "lecture": "3.3 Red Blood Cell Parameters", "level": "recall"}, {"q": "Name a cause of megaloblastic anaemia.", "a": ["B12 deficiency", "Folate deficiency", "Vitamin B12 deficiency"], "lecture": "3.4 Tales from the Haematology Clinic I", "level": "recall"}, {"q": "Cell producing antibodies?", "a": ["Plasma cell", "B cell", "B lymphocyte"], "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "Phagocyte first recruited in acute bacterial infection?", "a": "Neutrophil", "lecture": "3.5 White Blood Cells", "level": "recall"}, {"q": "Howell–Jolly bodies suggest reduced function of?", "a": "Spleen", "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "inference"}, {"q": "Factor IX deficiency causes which haemophilia?", "a": "B", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "vWF binds platelets to?", "a": ["Collagen", "Subendothelium", "Exposed collagen"], "lecture": "3.8 Haemostasis", "level": "understanding"}, {"q": "Anticoagulant monitored by INR?", "a": "Warfarin", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Universal recipient for red cells (ABO)?", "a": "AB", "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Major Rh antigen of clinical importance?", "a": "D", "lecture": "3.9 Blood Transfusion", "level": "recall"}, {"q": "Name an acute-phase protein used as inflammation marker.", "a": ["CRP", "C-reactive protein"], "lecture": "3.10 Plasma", "level": "recall"}, {"q": "Iron stored intracellularly mainly as?", "a": "Ferritin", "lecture": "3.10 Plasma", "level": "recall"}], "saq": [{"q": "Explain cooperative oxygen binding in haemoglobin and why the dissociation curve is sigmoidal.", "a": "Binding of O2 to one subunit increases affinity of remaining subunits (positive cooperativity). This produces a sigmoidal curve: steep unloading over tissue PO2 ranges while still loading efficiently in the lungs.", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "A patient has fatigue, low haemoglobin, low MCV and low ferritin. Interpret these findings and outline first-line management principles.", "a": "Findings indicate iron-deficiency anaemia. Investigate and treat the cause of iron loss/poor intake/absorption, and replace iron (oral or IV as appropriate) while monitoring response (reticulocytes, Hb, ferritin).", "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Compare the roles of neutrophils, eosinophils and lymphocytes in host defence.", "a": "Neutrophils are first-line phagocytes against bacteria/fungi. Eosinophils contribute to defence against parasites and allergic inflammation. Lymphocytes mediate adaptive immunity (B cells antibodies; T cells cellular immunity/help).", "lecture": "3.5 White Blood Cells", "level": "understanding"}, {"q": "Describe primary versus secondary haemostasis.", "a": "Primary haemostasis: vascular spasm and platelet plug formation (adhesion via vWF/GPIb, aggregation via GPIIb/IIIa and fibrinogen). Secondary haemostasis: coagulation cascade generating thrombin and fibrin that stabilises the plug.", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Explain why group O red cells are preferred as emergency universal donor units, and why plasma compatibility differs.", "a": "Group O RBCs lack A and B antigens so are less likely to be haemolysed by recipient isoagglutinins. Plasma contains antibodies: AB plasma lacks anti-A/B and is the universal plasma donor, whereas O plasma contains both antibodies.", "lecture": "3.9 Blood Transfusion", "level": "inference"}, {"q": "A patient on warfarin has a high INR and minor bleeding. Explain the pharmacological basis and typical reversal approach in principle.", "a": "Warfarin blocks vitamin K epoxide reductase, reducing γ-carboxylation of factors II, VII, IX, X. Raised INR reflects impaired extrinsic pathway. Reversal may include withholding warfarin, vitamin K, and in serious bleeding prothrombin complex concentrate (per guidelines).", "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "How can electrophoresis of haemoglobin help diagnose sickle cell disease or thalassaemia trait?", "a": "Different haemoglobins migrate differently based on charge. Patterns can identify HbS, quantify HbA2/HbF, and support diagnoses such as sickle cell disease versus trait or β-thalassaemia trait when combined with red-cell indices and clinical context.", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "application"}, {"q": "Outline why albumin is important for plasma oncotic pressure and drug transport.", "a": "Albumin is the most abundant plasma protein and a major contributor to colloid osmotic pressure, retaining fluid in the vascular space. It also binds and transports many hormones, fatty acids, ions and drugs.", "lecture": "3.10 Plasma", "level": "understanding"}, {"q": "Interpret a blood film showing spherocytes and polychromasia in a jaundiced patient.", "a": "Spherocytes suggest membrane loss (hereditary spherocytosis or immune haemolysis). Polychromasia indicates reticulocytosis—a marrow response to haemolysis or blood loss. With jaundice this supports haemolytic anaemia; further tests (DAT, bilirubin, LDH, haptoglobin) refine the cause.", "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "inference"}, {"q": "Describe Landsteiner’s law and its relevance to ABO crossmatching.", "a": "Individuals produce antibodies against ABO antigens absent from their own red cells (e.g. group A has anti-B). Crossmatching must ensure donor RBCs lack antigens targeted by recipient antibodies to prevent acute haemolytic transfusion reactions.", "lecture": "3.9 Blood Transfusion", "level": "understanding"}, {"q": "Explain how MCV, MCH and RDW help classify anaemias.", "a": "MCV classifies micro/normo/macrocytic; MCH reflects haemoglobin content (hypochromia). RDW indicates anisocytosis—often raised early in iron deficiency or mixed deficiencies—helping narrow differential beyond a single index.", "lecture": "3.3 Red Blood Cell Parameters", "level": "application"}, {"q": "Why might a raised CRP and polyclonal rise in gamma-globulins appear together in infection?", "a": "CRP is an acute-phase reactant rising with inflammation/infection. Gamma-globulins include immunoglobulins; polyclonal increase reflects humoral response to infection. Together they support an inflammatory/infectious process rather than a monoclonal paraprotein alone.", "lecture": "3.10 Plasma", "level": "inference"}, {"q": "Explain how hypoxia increases red-cell mass via erythropoietin.", "a": "Renal hypoxia stimulates EPO release. EPO acts on marrow erythroid progenitors to increase red-cell production, raising oxygen-carrying capacity over days.", "lecture": "3.1 Red Blood Cells", "level": "understanding"}, {"q": "Describe factors that cause a right shift of the oxygen dissociation curve and the physiological benefit.", "a": "Increased CO2, H+ (Bohr effect), temperature and 2,3-BPG reduce Hb–O2 affinity (right shift), facilitating unloading in metabolically active tissues.", "lecture": "3.2 Haemoglobin Spectrophotometry and Electrophoresis", "level": "understanding"}, {"q": "How would you approach classifying an anaemia using MCV and clinical context?", "a": "Use MCV to split micro/normo/macrocytic, then integrate film, reticulocyte count, haematinics, and history (bleeding, diet, chronic disease, drugs) to narrow causes.", "lecture": "3.3 Red Blood Cell Parameters", "level": "application"}, {"q": "Compare iron-deficiency and anaemia of chronic disease laboratory patterns in principle.", "a": "Iron deficiency: low ferritin, low serum iron, high TIBC/transferrin. Anaemia of chronic disease: iron restricted with often normal/high ferritin (acute phase), low TIBC, low serum iron.", "lecture": "3.4 Tales from the Haematology Clinic I", "level": "application"}, {"q": "Explain left shift in the neutrophil series and its clinical meaning.", "a": "Left shift means increased immature neutrophils (bands/earlier forms) in blood, typically reflecting acute demand such as bacterial infection or inflammation.", "lecture": "3.5 White Blood Cells", "level": "understanding"}, {"q": "Why is the blood film still valuable despite automated counters?", "a": "Film detects morphology machines miss: fragments, parasites, blasts, abnormal white-cell morphology, platelet clumps falsely lowering counts, and clues to specific diagnoses.", "lecture": "3.6 Diagnostic Role of the Blood Film", "level": "inference"}, {"q": "Outline the coagulation cascade concept of extrinsic, intrinsic and common pathways.", "a": "Extrinsic: tissue factor–VIIa. Intrinsic: contact factors leading to IXa–VIIIa. Both activate X to Xa (common pathway) generating thrombin, which converts fibrinogen to fibrin.", "lecture": "3.8 Haemostasis", "level": "recall"}, {"q": "Explain why platelet disorders tend to cause mucocutaneous bleeding whereas coagulation factor deficiencies cause deep haematomas/haemarthroses.", "a": "Platelets form the initial plug critical for small-vessel and mucosal haemostasis. Fibrin stabilisation defects allow larger, delayed deep bleeding into joints/muscles.", "lecture": "3.8 Haemostasis", "level": "inference"}, {"q": "Describe the immunological basis of an acute ABO haemolytic transfusion reaction.", "a": "Preformed IgM isoagglutinins bind incompatible RBC antigens, activate complement, and cause intravascular haemolysis with fever, hypotension, haemoglobinuria and risk of DIC/renal injury.", "lecture": "3.9 Blood Transfusion", "level": "application"}, {"q": "What is the role of transferrin and how does transferrin saturation help assess iron status?", "a": "Transferrin transports plasma iron to tissues via receptors. Saturation (serum iron/TIBC) falls in iron deficiency and can rise in overload; interpret with ferritin and inflammation.", "lecture": "3.10 Plasma", "level": "understanding"}, {"q": "Explain vaso-occlusion in sickle cell disease in pathophysiological terms.", "a": "Deoxygenated HbS polymerises, sickling red cells that are rigid and adhesive. They obstruct microvasculature, causing ischaemic pain crises and organ damage, worsened by dehydration/hypoxia.", "lecture": "3.7 Tales from the Haematology Clinic II", "level": "understanding"}, {"q": "A patient has prolonged APTT, normal PT/INR, and bleeding. What differential considerations follow?", "a": "Consider intrinsic pathway defects (VIII, IX, XI), inhibitors, or lupus anticoagulant (which prolongs APTT but usually thrombosis). Mixing studies and factor assays distinguish deficiency vs inhibitor; correlate clinically.", "lecture": "3.8 Haemostasis", "level": "application"}, {"q": "Why can CRP be high while albumin is low in severe inflammation?", "a": "Liver prioritises acute-phase protein synthesis (CRP up) while albumin production may fall (negative acute-phase reactant), and capillary leak can further lower measured albumin.", "lecture": "3.10 Plasma", "level": "inference"}]}, "immunity": {"sba": [{"q": "Which statement best defines a virus?", "a": "An infectious obligate intracellular parasite", "options": ["An infectious obligate intracellular parasite", "A free-living prokaryote with peptidoglycan", "A fungus with chitin cell walls only", "A multicellular parasite with digestive tract"], "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "Live attenuated vaccines generally induce stronger cellular immunity than killed vaccines because they:", "a": "Replicate to a limited extent and engage broader immune pathways", "options": ["Replicate to a limited extent and engage broader immune pathways", "Contain only polysaccharides without protein", "Never stimulate memory B cells", "Are unable to induce antibodies"], "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Type I hypersensitivity is mediated primarily by:", "a": "IgE and mast cell degranulation", "options": ["IgE and mast cell degranulation", "IgG against cell surfaces only", "Immune complex deposition only", "CD8 T-cell cytotoxicity only"], "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "Anaphylaxis is a medical emergency of which hypersensitivity type?", "a": "Type I", "options": ["Type I", "Type II", "Type III", "Type IV"], "lecture": "4.9 Anaphylaxis", "level": "recall"}, {"q": "First-line emergency treatment of anaphylaxis is:", "a": "Intramuscular adrenaline", "options": ["Intramuscular adrenaline", "Oral antihistamine alone", "IV antibiotics alone", "High-dose oral prednisolone alone as first step"], "lecture": "4.9 Anaphylaxis", "level": "application"}, {"q": "Central immune tolerance primarily develops in which primary lymphoid organs?", "a": "Thymus (T cells) and bone marrow (B cells)", "options": ["Thymus (T cells) and bone marrow (B cells)", "Only lymph nodes", "Only spleen red pulp", "Only Peyer’s patches"], "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "CD8 cytotoxic T cells recognise antigen presented on:", "a": "MHC class I", "options": ["MHC class I", "MHC class II", "Only IgM", "Only complement C3b"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "CD4 helper T cells typically recognise antigen on:", "a": "MHC class II", "options": ["MHC class II", "MHC class I only", "Only ABO antigens", "Only Toll-like receptors"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "A pathogen that downregulates MHC class I on infected cells is most likely trying to evade:", "a": "CD8 T-cell recognition", "options": ["CD8 T-cell recognition", "Neutrophil chemotaxis only", "Complement alternative pathway only", "IgE-mediated allergy only"], "lecture": "4.8 Immune Evasion", "level": "inference"}, {"q": "β-lactam antibiotics inhibit bacterial growth mainly by targeting:", "a": "Peptidoglycan cell wall synthesis", "options": ["Peptidoglycan cell wall synthesis", "Viral reverse transcriptase", "Fungal ergosterol only", "Human ribosomes"], "lecture": "4.3 Antimicrobial Therapies", "level": "understanding"}, {"q": "Broad-spectrum antibiotics increase risk of C. difficile colitis mainly because they:", "a": "Disrupt protective gut flora allowing C. difficile overgrowth", "options": ["Disrupt protective gut flora allowing C. difficile overgrowth", "Directly mutate C. difficile toxin genes", "Stimulate IgE against C. difficile", "Inhibit gastric acid only"], "lecture": "4.5 Diagnostic Bacteriology II", "level": "application"}, {"q": "Secondary lymphoid organs (e.g. lymph nodes, spleen) are specialised for:", "a": "Adaptive immune activation and antigen encounter", "options": ["Adaptive immune activation and antigen encounter", "Only haematopoiesis of all lineages", "Only filtration of CSF", "Only production of digestive enzymes"], "lecture": "4.2 Lymphoid Tissues", "level": "understanding"}, {"q": "Herd immunity is most effective when:", "a": "A sufficient proportion of the population is immune, limiting transmission", "options": ["A sufficient proportion of the population is immune, limiting transmission", "Only one person is vaccinated", "Antibiotics are given to everyone weekly", "Pathogens cannot mutate ever"], "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "PCR amplifies nucleic acid. Which enzyme is classically heat-stable for thermal cycling?", "a": "Taq polymerase", "options": ["Taq polymerase", "Pepsin", "Amylase", "Trypsin"], "lecture": "4.11 Diagnostic Virology I", "level": "recall"}, {"q": "Acyclovir is particularly useful against which virus family?", "a": "Herpesviruses (e.g. HSV)", "options": ["Herpesviruses (e.g. HSV)", "All RNA viruses equally", "Only hepatitis C", "Only influenza A"], "lecture": "4.10 Anti-Viral Agents", "level": "application"}, {"q": "Type IV hypersensitivity differs from types I–III because it is:", "a": "T-cell mediated (delayed)", "options": ["T-cell mediated (delayed)", "Always IgE mediated", "Always complement independent and immediate within seconds", "Caused only by ABO mismatch"], "lecture": "4.15 Hypersensitivity", "level": "understanding"}, {"q": "Passive immunotherapy with IVIG provides:", "a": "Immediate but temporary antibody-mediated protection", "options": ["Immediate but temporary antibody-mediated protection", "Lifelong active memory without antigen", "Only cell-mediated memory CD8 clones", "Sterilisation of the gut microbiome"], "lecture": "4.13 Vaccination", "level": "inference"}, {"q": "Gram-positive bacteria typically stain purple because of:", "a": "A thick peptidoglycan layer retaining crystal violet", "options": ["A thick peptidoglycan layer retaining crystal violet", "An outer LPS membrane only", "Absence of cell wall", "Capsule made of RNA"], "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "Which innate cells are especially important early sensors via pattern recognition receptors?", "a": "Macrophages and dendritic cells (among others)", "options": ["Macrophages and dendritic cells (among others)", "Only plasma cells", "Only mature erythrocytes", "Only megakaryocytes"], "lecture": "4.14 Immune Response to Infection", "level": "understanding"}, {"q": "A neonate tests antibody-positive for HIV. Why might PCR be preferred to confirm infection?", "a": "Maternal IgG can persist and confound antibody tests", "options": ["Maternal IgG can persist and confound antibody tests", "Neonates never produce any immune response", "PCR detects only maternal DNA", "Antibodies always mean active viral replication"], "lecture": "4.12 Diagnostic Virology II", "level": "application"}, {"q": "Pathogen-associated molecular patterns (PAMPs) are recognised by:", "a": "Pattern recognition receptors (e.g. TLRs)", "options": ["Pattern recognition receptors (e.g. TLRs)", "Only T-cell receptors exclusively", "Only ABO antibodies", "Only haemoglobin"], "lecture": "4.1 Microbial Infection", "level": "recall"}, {"q": "The spleen’s white pulp is specialised for:", "a": "Adaptive immune responses to blood-borne antigens", "options": ["Adaptive immune responses to blood-borne antigens", "Only bile storage", "Only erythropoietin production", "Only surfactant synthesis"], "lecture": "4.2 Lymphoid Tissues", "level": "understanding"}, {"q": "Bacteriostatic antibiotics:", "a": "Inhibit growth without necessarily killing immediately", "options": ["Inhibit growth without necessarily killing immediately", "Always sterilise in one dose", "Only work on viruses", "Replace vaccination"], "lecture": "4.3 Antimicrobial Therapies", "level": "understanding"}, {"q": "Gram-negative outer membrane contains which endotoxin component?", "a": "LPS (lipopolysaccharide)", "options": ["LPS (lipopolysaccharide)", "Peptidoglycan only", "Teichoic acid only", "Chitin"], "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "Catalase-positive organisms can break down:", "a": "Hydrogen peroxide", "options": ["Hydrogen peroxide", "Peptidoglycan", "DNA only", "Lactose only"], "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "Affinity maturation of antibodies occurs mainly in:", "a": "Germinal centres of secondary lymphoid tissues", "options": ["Germinal centres of secondary lymphoid tissues", "Only the thymic cortex for B cells", "Only red-cell cytoplasm", "Only the gallbladder"], "lecture": "4.6 Lymphocytes", "level": "understanding"}, {"q": "Isotype (class) switching changes:", "a": "The heavy-chain constant region (e.g. IgM to IgG)", "options": ["The heavy-chain constant region (e.g. IgM to IgG)", "Antigen specificity of the variable region always randomly", "MHC haplotype", "ABO blood group"], "lecture": "4.6 Lymphocytes", "level": "understanding"}, {"q": "Regulatory T cells help maintain tolerance by:", "a": "Suppressing effector immune responses to self/harmless antigens", "options": ["Suppressing effector immune responses to self/harmless antigens", "Always activating complement C1", "Producing IgE only", "Lysing all B cells indiscriminately"], "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "Antigenic variation helps pathogens evade immunity by:", "a": "Changing surface epitopes so prior antibodies bind poorly", "options": ["Changing surface epitopes so prior antibodies bind poorly", "Increasing MHC I expression always", "Stopping all replication forever", "Converting to prions only"], "lecture": "4.8 Immune Evasion", "level": "understanding"}, {"q": "Which mediator from mast cells causes vasodilation and increased permeability in allergy?", "a": "Histamine", "options": ["Histamine", "Erythropoietin", "Insulin", "Vitamin K"], "lecture": "4.9 Anaphylaxis", "level": "recall"}, {"q": "Neuraminidase inhibitors act on influenza by:", "a": "Blocking viral release from infected cells", "options": ["Blocking viral release from infected cells", "Inhibiting bacterial peptidoglycan", "Blocking IgE permanently", "Raising haemoglobin"], "lecture": "4.10 Anti-Viral Agents", "level": "application"}, {"q": "Serology diagnosing infection often detects:", "a": "Pathogen-specific antibodies (or antigens)", "options": ["Pathogen-specific antibodies (or antigens)", "Only karyotype abnormalities", "Only MCV", "Only creatinine kinase"], "lecture": "4.11 Diagnostic Virology I", "level": "recall"}, {"q": "Window period in HIV testing refers to:", "a": "Time after infection before tests become reliably positive", "options": ["Time after infection before tests become reliably positive", "Lifelong vaccine immunity", "Only the incubation of tetanus", "Time to platelet plug formation"], "lecture": "4.12 Diagnostic Virology II", "level": "understanding"}, {"q": "Conjugate vaccines improve responses to polysaccharides by:", "a": "Engaging T-cell help via a protein carrier", "options": ["Engaging T-cell help via a protein carrier", "Removing all adjuvants", "Only containing live virus", "Blocking MHC II permanently"], "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Opsonisation facilitates:", "a": "Phagocytosis by marking microbes with antibody/complement", "options": ["Phagocytosis by marking microbes with antibody/complement", "Viral uncoating only", "DNA ligation", "Bile acid synthesis"], "lecture": "4.14 Immune Response to Infection", "level": "recall"}, {"q": "Type II hypersensitivity examples include:", "a": "Immune haemolytic anaemia / ABO mismatch", "options": ["Immune haemolytic anaemia / ABO mismatch", "Only poison ivy delayed dermatitis exclusively", "Only anaphylaxis exclusively", "Only serum sickness exclusively"], "lecture": "4.15 Hypersensitivity", "level": "application"}, {"q": "Type III hypersensitivity is driven by:", "a": "Immune complex deposition and complement/inflammation", "options": ["Immune complex deposition and complement/inflammation", "Only IgE on mast cells", "Only CD8 killing of virally infected cells as the definition", "Only haemoglobin polymerisation"], "lecture": "4.15 Hypersensitivity", "level": "understanding"}, {"q": "Memory B and T cells enable faster secondary responses because they:", "a": "Are expanded and primed for rapid reactivation on re-exposure", "options": ["Are expanded and primed for rapid reactivation on re-exposure", "Eliminate the need for antigen ever again", "Are only neutrophils", "Are erythrocytes"], "lecture": "4.14 Immune Response to Infection", "level": "inference"}, {"q": "A killed vaccine cannot cause progressive infection in immunocompromised hosts like a live vaccine might because:", "a": "It contains non-replicating antigen", "options": ["It contains non-replicating antigen", "It always induces stronger CD8 responses than live vaccines", "It contains only live organisms", "It permanently deletes Tregs"], "lecture": "4.13 Vaccination", "level": "inference"}, {"q": "Complement classical pathway is typically initiated by:", "a": "Antibody–antigen complexes (IgM/IgG)", "options": ["Antibody–antigen complexes (IgM/IgG)", "Only mannose-binding lectin exclusively as the definition of classical", "Only alternative pathway tickover as classical definition", "Only erythropoietin"], "lecture": "4.14 Immune Response to Infection", "level": "recall"}], "vsaq": [{"q": "Name the antibody class central to type I hypersensitivity.", "a": "IgE", "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "First-line drug for anaphylaxis?", "a": "Adrenaline", "lecture": "4.9 Anaphylaxis", "level": "recall"}, {"q": "CD8 T cells recognise antigen on which MHC class?", "a": ["MHC I", "MHC class I", "HLA class I"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "CD4 T cells recognise antigen on which MHC class?", "a": ["MHC II", "MHC class II", "HLA class II"], "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "Name the primary lymphoid organ for T-cell maturation.", "a": "Thymus", "lecture": "4.2 Lymphoid Tissues", "level": "recall"}, {"q": "β-lactams target synthesis of what bacterial structure?", "a": "Peptidoglycan", "lecture": "4.3 Antimicrobial Therapies", "level": "recall"}, {"q": "Name a live attenuated viral vaccine example.", "a": ["MMR", "Oral polio", "Yellow fever", "Varicella"], "lecture": "4.13 Vaccination", "level": "recall"}, {"q": "Herd immunity reduces what between hosts?", "a": "Transmission", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "PCR uses which heat-stable polymerase classically?", "a": "Taq polymerase", "lecture": "4.11 Diagnostic Virology I", "level": "recall"}, {"q": "Acyclovir is a nucleoside analogue used mainly against?", "a": ["HSV", "Herpesviruses", "Herpes"], "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "Gram-positive organisms retain which primary stain?", "a": "Crystal violet", "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "C. difficile colitis is linked to disruption of?", "a": ["Gut flora", "Microbiome", "Normal flora"], "lecture": "4.5 Diagnostic Bacteriology II", "level": "understanding"}, {"q": "Type IV hypersensitivity timing is described as?", "a": "Delayed", "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "Name the process deleting strongly self-reactive thymocytes.", "a": ["Negative selection", "Central tolerance"], "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "Obligate intracellular parasite composed of nucleic acid in a protein coat?", "a": "Virus", "lecture": "4.1 Microbial Infection", "level": "recall"}, {"q": "IVIG is an example of which immunity type?", "a": "Passive", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Neuraminidase inhibitors are used against which virus?", "a": "Influenza", "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "Name secondary lymphoid organs filtering blood.", "a": "Spleen", "lecture": "4.2 Lymphoid Tissues", "level": "recall"}, {"q": "TLR stands for?", "a": "Toll-like receptor", "lecture": "4.1 Microbial Infection", "level": "recall"}, {"q": "Primary lymphoid organ producing B cells in adults?", "a": ["Bone marrow", "Marrow"], "lecture": "4.2 Lymphoid Tissues", "level": "recall"}, {"q": "Antibiotic that kills bacteria outright is called?", "a": "Bactericidal", "lecture": "4.3 Antimicrobial Therapies", "level": "recall"}, {"q": "LPS is found in which Gram category mainly?", "a": ["Gram-negative", "Gram negative"], "lecture": "4.4 Diagnostic Bacteriology I", "level": "recall"}, {"q": "Antibody class first produced in a primary response?", "a": "IgM", "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "Main antibody in serum after class switching often?", "a": "IgG", "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "Mucosal antibody class?", "a": "IgA", "lecture": "4.6 Lymphocytes", "level": "recall"}, {"q": "Cells that suppress autoimmunity include regulatory?", "a": ["T cells", "Tregs", "Treg"], "lecture": "4.7 Immune Tolerance", "level": "recall"}, {"q": "Trypanosomes evade immunity partly by antigenic?", "a": "Variation", "lecture": "4.8 Immune Evasion", "level": "recall"}, {"q": "Adrenaline autoinjector route in anaphylaxis?", "a": ["IM", "Intramuscular"], "lecture": "4.9 Anaphylaxis", "level": "application"}, {"q": "Tamiflu is an example of which inhibitor class?", "a": "Neuraminidase", "lecture": "4.10 Anti-Viral Agents", "level": "recall"}, {"q": "qPCR quantifies what in viral load testing?", "a": ["Nucleic acid", "Viral RNA", "Viral DNA", "Genome copies"], "lecture": "4.11 Diagnostic Virology I", "level": "understanding"}, {"q": "HIV primarily infects cells expressing CD4 and a?", "a": ["Co-receptor", "CCR5", "CXCR4"], "lecture": "4.12 Diagnostic Virology II", "level": "recall"}, {"q": "Adjuvants in vaccines enhance the?", "a": "Immune response", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "C3b coating microbes aids?", "a": "Opsonisation", "lecture": "4.14 Immune Response to Infection", "level": "recall"}, {"q": "Mantoux/TB skin test is which hypersensitivity type?", "a": ["IV", "Type IV", "Delayed"], "lecture": "4.15 Hypersensitivity", "level": "application"}, {"q": "Serum sickness is classic for which hypersensitivity?", "a": ["III", "Type III"], "lecture": "4.15 Hypersensitivity", "level": "recall"}], "saq": [{"q": "Compare active and passive immunisation, giving one clinical example of each.", "a": "Active immunisation stimulates the host adaptive system to generate lasting memory (e.g. vaccines). Passive immunisation transfers ready-made antibodies for immediate temporary protection (e.g. IVIG, antivenom, maternal IgG).", "lecture": "4.13 Vaccination", "level": "understanding"}, {"q": "Outline the pathophysiology of type I hypersensitivity leading to anaphylaxis.", "a": "Prior sensitisation produces allergen-specific IgE bound to mast cells/basophils. Re-exposure cross-links IgE, causing degranulation with histamine and mediators → vasodilation, permeability, bronchospasm, and potentially shock.", "lecture": "4.9 Anaphylaxis", "level": "application"}, {"q": "Explain how MHC class I versus class II pathways direct different T-cell responses.", "a": "MHC I presents cytosolic peptides to CD8 T cells (kill infected/abnormal cells). MHC II on APCs presents extracellular/processed peptides to CD4 T cells, which help B cells and orchestrate adaptive responses.", "lecture": "4.6 Lymphocytes", "level": "understanding"}, {"q": "Describe two strategies pathogens use to evade the immune system.", "a": "Examples: antigenic variation; latency; downregulation of MHC I; inhibition of phagosome–lysosome fusion; capsule preventing phagocytosis; molecular mimicry; secretion of immunomodulatory proteins. (Any two well explained.)", "lecture": "4.8 Immune Evasion", "level": "recall"}, {"q": "A patient develops watery diarrhoea after broad-spectrum antibiotics. Explain the likely mechanism involving C. difficile.", "a": "Antibiotics deplete competing gut flora. C. difficile can overgrow and produce toxins that damage colonic epithelium, causing colitis/diarrhoea. Risk is higher with broad-spectrum agents and hospital exposure.", "lecture": "4.5 Diagnostic Bacteriology II", "level": "application"}, {"q": "Why are live vaccines usually contraindicated in markedly immunocompromised patients?", "a": "Attenuated organisms may cause disease if host immunity cannot control limited replication. Killed/subunit vaccines are generally safer though sometimes less immunogenic.", "lecture": "4.13 Vaccination", "level": "inference"}, {"q": "Explain the principle of PCR and why nested or real-time PCR is useful in viral diagnostics.", "a": "PCR uses primers and a thermostable polymerase to amplify specific nucleic acid sequences through thermal cycles. Nested PCR increases specificity; qPCR quantifies product in real time (e.g. viral load).", "lecture": "4.11 Diagnostic Virology I", "level": "understanding"}, {"q": "Distinguish the four classical hypersensitivity types with one example each.", "a": "I: IgE/mast cell (anaphylaxis, allergy). II: IgG/IgM against cell surfaces (autoimmune haemolysis, ABO mismatch). III: immune complexes (serum sickness, SLE nephritis). IV: T-cell delayed (TB skin test, contact dermatitis).", "lecture": "4.15 Hypersensitivity", "level": "recall"}, {"q": "Outline how innate recognition of PAMPs initiates an adaptive response.", "a": "PRRs on innate cells detect PAMPs → cytokine/chemokine release, inflammation, and dendritic cell activation/maturation. Activated DCs migrate to lymph nodes and present antigen with costimulation to naïve T cells, linking innate to adaptive immunity.", "lecture": "4.14 Immune Response to Infection", "level": "inference"}, {"q": "Explain central tolerance and what may happen if it fails.", "a": "In thymus/bone marrow, strongly self-reactive clones are deleted or diverted (e.g. Treg selection). Failure can allow autoreactive lymphocytes to mature, contributing to autoimmune disease; peripheral tolerance mechanisms normally provide backup.", "lecture": "4.7 Immune Tolerance", "level": "understanding"}, {"q": "How does selective toxicity underpin antibacterial therapy, using cell wall synthesis as an example?", "a": "Antibacterials target structures/processes essential to microbes but absent/different in humans. β-lactams inhibit peptidoglycan cross-linking in bacterial walls—humans lack peptidoglycan—yielding selective toxicity.", "lecture": "4.3 Antimicrobial Therapies", "level": "application"}, {"q": "A baby born to an HIV-positive mother has positive HIV serology at 6 weeks. Discuss interpretation and a better confirmatory approach.", "a": "Maternal IgG crosses the placenta and can persist, so antibody tests may be positive without infant infection. Nucleic acid testing (e.g. HIV RNA/DNA PCR) is used to diagnose infection in young infants.", "lecture": "4.12 Diagnostic Virology II", "level": "application"}, {"q": "Explain how innate and adaptive immunity differ in specificity and memory.", "a": "Innate responses are rapid, use germline-encoded PRRs, and lack antigen-specific memory. Adaptive responses are slower initially, highly specific via TCRs/BCRs, and generate memory for faster secondary responses.", "lecture": "4.1 Microbial Infection", "level": "understanding"}, {"q": "Describe the anatomical organisation that allows lymph nodes to activate adaptive immunity.", "a": "Afferent lymph brings antigen/APCs into the node. B-cell follicles and T-cell zones enable antigen presentation, lymphocyte activation, germinal centre reactions, and exit of effectors via efferent lymph.", "lecture": "4.2 Lymphoid Tissues", "level": "understanding"}, {"q": "Why does combining antibiotics sometimes help, and when can antagonism occur?", "a": "Synergy can broaden coverage or enhance killing (e.g. different targets). Antagonism can occur if a bacteriostatic agent reduces activity of a bactericidal drug that needs growth, so combinations must be rational.", "lecture": "4.3 Antimicrobial Therapies", "level": "inference"}, {"q": "Outline how Gram stain and culture contribute to bacterial diagnosis.", "a": "Gram stain rapidly suggests morphology and Gram status guiding empiric therapy. Culture grows the organism for identification and susceptibility testing to refine antibiotics.", "lecture": "4.4 Diagnostic Bacteriology I", "level": "application"}, {"q": "Explain clonal selection in lymphocyte responses.", "a": "Lymphocytes with receptors specific for an antigen are selectively activated, proliferate, and differentiate into effectors and memory cells, amplifying the useful clones.", "lecture": "4.6 Lymphocytes", "level": "understanding"}, {"q": "How does molecular mimicry contribute to autoimmunity?", "a": "Pathogen antigens resembling self can prime cross-reactive lymphocytes. After infection clears, those clones may attack host tissues sharing epitopes.", "lecture": "4.7 Immune Tolerance", "level": "inference"}, {"q": "Describe latency as a viral immune evasion strategy with an example.", "a": "Latency involves limited gene expression so few antigens are presented, allowing persistence (e.g. herpesviruses). Periodic reactivation can cause disease when immunity wanes.", "lecture": "4.8 Immune Evasion", "level": "application"}, {"q": "Write an ABCDE-style priority list conceptually for anaphylaxis management (key first steps).", "a": "Call for help; airway support; give IM adrenaline promptly; high-flow oxygen; lie patient flat with legs elevated if breathing allows; IV fluids for shock; antihistamines/steroids are adjuncts, not first-line for airway/circulation.", "lecture": "4.9 Anaphylaxis", "level": "application"}, {"q": "Explain selective toxicity of acyclovir for herpesvirus-infected cells.", "a": "Viral thymidine kinase preferentially phosphorylates acyclovir in infected cells; cellular kinases complete activation. The triphosphate inhibits viral DNA polymerase and terminates chains, sparing uninfected cells relatively.", "lecture": "4.10 Anti-Viral Agents", "level": "understanding"}, {"q": "Compare antigen tests, antibody tests and NAAT for diagnosing viral infection.", "a": "Antigen/NAAT detect pathogen components/genome (current infection). Antibodies indicate exposure/response and may lag (window period) or reflect past infection/vaccination depending on assay.", "lecture": "4.12 Diagnostic Virology II", "level": "understanding"}, {"q": "Why are boosters sometimes needed after primary vaccination?", "a": "Antibody/memory can wane, and boosters re-expand memory pools to restore protective titres. Some antigens are weakly immunogenic and need repeated exposure for durable immunity.", "lecture": "4.13 Vaccination", "level": "inference"}, {"q": "Explain how complement contributes to host defence beyond MAC lysis.", "a": "Complement opsonises (C3b), generates anaphylatoxins (C3a/C5a) recruiting leukocytes, and clears immune complexes—supporting inflammation and phagocytosis even without full MAC lysis.", "lecture": "4.14 Immune Response to Infection", "level": "understanding"}, {"q": "A patient has fever, urticaria and arthralgia 10 days after antitoxin. What hypersensitivity mechanism fits?", "a": "Type III serum sickness: immune complexes deposit in tissues, activate complement and inflammation, causing systemic symptoms days after antigen exposure.", "lecture": "4.15 Hypersensitivity", "level": "application"}]}, "genetics": {"sba": [{"q": "Autosomal dominant inheritance typically means:", "a": "One mutant allele is sufficient to express the phenotype", "options": ["One mutant allele is sufficient to express the phenotype", "Both alleles must be mutant to express the phenotype", "Only males are affected", "The trait skips every generation always"], "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Autosomal recessive disease in a child of unaffected parents most likely implies:", "a": "Both parents are heterozygous carriers", "options": ["Both parents are heterozygous carriers", "Both parents are homozygous affected", "Father alone transmitted a Y-linked allele", "Mitochondrial inheritance from father"], "lecture": "5.1 Modes of Inheritance", "level": "application"}, {"q": "X-linked recessive disorders are more often clinically expressed in:", "a": "Males (hemizygous for X)", "options": ["Males (hemizygous for X)", "Females only", "Equally in both sexes always", "Only postmenopausal women"], "lecture": "5.1 Modes of Inheritance", "level": "understanding"}, {"q": "Trisomy 21 is an example of:", "a": "Aneuploidy", "options": ["Aneuploidy", "A single nucleotide polymorphism only", "Trinucleotide expansion only", "Mitochondrial deletion only"], "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Nondisjunction in meiosis primarily leads to:", "a": "Gametes with extra or missing chromosomes", "options": ["Gametes with extra or missing chromosomes", "Only silent synonymous codon changes", "Only epigenetic methylation changes", "Always balanced reciprocal translocation without risk"], "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "Complex (multifactorial) diseases are characterised by:", "a": "Combined effects of multiple genes and environment", "options": ["Combined effects of multiple genes and environment", "Strict Mendelian single-gene causation only", "Only chromosomal trisomies", "Only spontaneous new mutations each generation"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "understanding"}, {"q": "Pharmacogenetics is best described as:", "a": "How genetic variation affects drug response and toxicity", "options": ["How genetic variation affects drug response and toxicity", "Only the chemistry of tablet coatings", "Only bacterial resistance mechanisms", "Only vaccine cold-chain logistics"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Osteogenesis imperfecta (“brittle bone disease”) commonly involves defects in:", "a": "Collagen (often type I)", "options": ["Collagen (often type I)", "Haemoglobin β-chain only", "Dystrophin only", "Factor VIII only"], "lecture": "5.4 Brittle Bones", "level": "recall"}, {"q": "A germline mutation in a tumour suppressor such as BRCA1 increases cancer risk mainly by:", "a": "Impairing DNA repair / genomic stability across cells of the body", "options": ["Impairing DNA repair / genomic stability across cells of the body", "Affecting only one somatic cell forever", "Increasing dietary iron absorption only", "Blocking MHC class II expression only"], "lecture": "5.6 Cancer Genetics", "level": "inference"}, {"q": "Proto-oncogenes become oncogenes when:", "a": "Gain-of-function changes hyperactivate growth signalling", "options": ["Gain-of-function changes hyperactivate growth signalling", "Both copies are deleted like classic tumour suppressors only", "They solely encode structural ribosomal RNA", "They are never expressed in any cancer"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Which testing approach sequences many genes relevant to a phenotype in parallel?", "a": "Gene panel / next-generation sequencing panel", "options": ["Gene panel / next-generation sequencing panel", "Only karyotype for single-gene SNVs", "Only blood film morphology", "Only ESR"], "lecture": "5.7 Genetic Testing", "level": "recall"}, {"q": "Incomplete penetrance means:", "a": "Not everyone with the genotype shows the phenotype", "options": ["Not everyone with the genotype shows the phenotype", "The phenotype is always identical in severity", "Only mitochondrial DNA is involved", "The allele is never transmitted"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Variable expressivity means:", "a": "Severity/features differ among genotype-positive individuals", "options": ["Severity/features differ among genotype-positive individuals", "The genotype is never pathogenic", "Only one sex can inherit the allele", "Penetrance is always 100% with identical features"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "CRISPR-based approaches for genetic disease aim primarily to:", "a": "Edit or modulate specific DNA sequences", "options": ["Edit or modulate specific DNA sequences", "Replace all chromosomes each cell division", "Only measure karyotypes", "Only inhibit platelet aggregation"], "lecture": "5.9 Emerging Treatments", "level": "recall"}, {"q": "A balanced reciprocal translocation carrier is usually healthy but has increased risk of:", "a": "Unbalanced gametes and affected offspring", "options": ["Unbalanced gametes and affected offspring", "Immediate trisomy in every cell of their body", "Inability to produce any gametes always", "Only mitochondrial disease"], "lecture": "5.2 Chromosomal Abnormalities", "level": "application"}, {"q": "Mitochondrial DNA disorders are transmitted:", "a": "From the mother (maternal inheritance)", "options": ["From the mother (maternal inheritance)", "Only from father to son", "Only autosomal recessive", "Never inherited"], "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "A pathogenic BRCA variant is identified in a family. Cascade testing of relatives is mainly to:", "a": "Identify carriers for risk-reducing options and surveillance", "options": ["Identify carriers for risk-reducing options and surveillance", "Treat already established metastases only", "Replace chemotherapy for all cancers", "Diagnose bacterial infection"], "lecture": "5.6 Cancer Genetics", "level": "application"}, {"q": "SNP association studies in complex disease typically identify:", "a": "Risk alleles of small effect that contribute probabilistically", "options": ["Risk alleles of small effect that contribute probabilistically", "A single mutation that is necessary and sufficient in all cases", "Only large chromosomal trisomies", "Only non-genetic environmental causes"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "inference"}, {"q": "Anticipation in some repeat-expansion disorders refers to:", "a": "Earlier/more severe disease in successive generations as repeats expand", "options": ["Earlier/more severe disease in successive generations as repeats expand", "Complete disappearance of disease each generation", "Only maternal imprinting without repeats", "Always milder disease in grandchildren"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Gene therapy using a viral vector must balance transduction efficiency against:", "a": "Immune responses and insertional risks", "options": ["Immune responses and insertional risks", "Only the cost of karyotyping", "Only ABO matching of erythrocytes", "Only gastric pH"], "lecture": "5.9 Emerging Treatments", "level": "inference"}, {"q": "Consanguinity increases risk of autosomal recessive disease in offspring because:", "a": "Related parents are more likely to carry the same rare allele", "options": ["Related parents are more likely to carry the same rare allele", "It converts all traits to X-linked", "It prevents recombination forever", "It eliminates mitochondrial DNA"], "lecture": "5.1 Modes of Inheritance", "level": "inference"}, {"q": "Y-linked inheritance is characterised by:", "a": "Transmission from father to all sons, not to daughters", "options": ["Transmission from father to all sons, not to daughters", "Mother-to-all-children only", "Skipping males always", "Only mitochondrial pattern"], "lecture": "5.1 Modes of Inheritance", "level": "understanding"}, {"q": "Robertsonian translocation involves:", "a": "Fusion of two acrocentric chromosomes", "options": ["Fusion of two acrocentric chromosomes", "Only a point mutation in BRCA1", "Only trinucleotide expansion", "Only epigenetic imprinting without structural change"], "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Uniparental disomy means:", "a": "Both copies of a chromosome pair from one parent", "options": ["Both copies of a chromosome pair from one parent", "One chromosome from each of three parents", "Loss of all autosomes", "Only Y chromosome duplication in females"], "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "Imprinting disorders can arise when:", "a": "Parent-of-origin epigenetic marks are disturbed", "options": ["Parent-of-origin epigenetic marks are disturbed", "Only ABO antibodies form", "Only iron deficiency occurs", "Only live vaccines are given"], "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "Heritability estimates in complex disease describe:", "a": "Proportion of population variance attributable to genetic differences", "options": ["Proportion of population variance attributable to genetic differences", "Certainty that one gene causes every case", "Only chromosomal trisomy rates", "Drug tablet dissolution rate"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "understanding"}, {"q": "A CYP450 loss-of-function allele may cause:", "a": "Higher drug levels and toxicity for drugs needing that enzyme for clearance", "options": ["Higher drug levels and toxicity for drugs needing that enzyme for clearance", "Always faster clearance of all drugs", "Only changes in eye colour", "Only ABO switching"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "application"}, {"q": "Type I osteogenesis imperfecta is often milder than type II because:", "a": "Quantitative collagen reduction can be less severe than qualitative dominant-negative defects", "options": ["Quantitative collagen reduction can be less severe than qualitative dominant-negative defects", "Type I always lacks fractures", "Type II is not genetic", "Collagen is irrelevant in bone"], "lecture": "5.4 Brittle Bones", "level": "inference"}, {"q": "Loss of heterozygosity at a tumour suppressor locus refers to:", "a": "Somatic loss of the remaining wild-type allele", "options": ["Somatic loss of the remaining wild-type allele", "Gain of an extra wild-type copy always", "Only silent polymorphisms", "Mitochondrial inheritance"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Driver mutations in cancer are those that:", "a": "Confer selective growth advantage", "options": ["Confer selective growth advantage", "Are always synonymous and neutral", "Only occur in non-coding RNA never affecting phenotype", "Only determine eye colour"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Passenger mutations are best described as:", "a": "Mutations that hitchhike without driving the phenotype", "options": ["Mutations that hitchhike without driving the phenotype", "The only mutations that cause cancer", "Always germline pathogenic variants", "Always chromosomal trisomies"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Sanger sequencing is classically used to:", "a": "Read a targeted DNA region at high accuracy", "options": ["Read a targeted DNA region at high accuracy", "Measure serum ferritin", "Perform Gram stain", "Quantify CRP only"], "lecture": "5.7 Genetic Testing", "level": "recall"}, {"q": "A variant of uncertain significance (VUS) means:", "a": "Pathogenicity is not established; avoid over-interpreting clinically", "options": ["Pathogenicity is not established; avoid over-interpreting clinically", "It is proven benign always", "It is proven pathogenic always", "It changes blood group"], "lecture": "5.7 Genetic Testing", "level": "application"}, {"q": "Pleiotropy means:", "a": "One gene affects multiple phenotypic traits", "options": ["One gene affects multiple phenotypic traits", "Many genes affect one trait only by definition of pleiotropy", "Only chromosomal nondisjunction", "Only drug–drug interaction"], "lecture": "5.8 Phenotypic Variability", "level": "recall"}, {"q": "Genetic heterogeneity means:", "a": "Similar phenotypes can result from different genetic causes", "options": ["Similar phenotypes can result from different genetic causes", "One allele always causes identical severity", "Only mitochondrial inheritance", "Only Y-linked deafness"], "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": " Antisense oligonucleotide therapies often aim to:", "a": "Modulate RNA splicing or reduce toxic transcripts", "options": ["Modulate RNA splicing or reduce toxic transcripts", "Replace entire chromosomes nightly", "Only raise INR", "Only stain bacteria"], "lecture": "5.9 Emerging Treatments", "level": "application"}, {"q": "Exon skipping therapy is designed to:", "a": "Exclude an exon to restore reading frame/function where applicable", "options": ["Exclude an exon to restore reading frame/function where applicable", "Always insert an extra chromosome 21", "Block all transcription genome-wide", "Convert IgM to IgE"], "lecture": "5.9 Emerging Treatments", "level": "understanding"}, {"q": "Germline gene editing raises unique ethical issues because:", "a": "Changes can be heritable across generations", "options": ["Changes can be heritable across generations", "It only affects one red cell transiently ever", "It cannot alter DNA", "It is identical to giving a painkiller"], "lecture": "5.9 Emerging Treatments", "level": "inference"}, {"q": "If an AD condition shows 70% penetrance, among genotype-positive people:", "a": "About 70% manifest the phenotype (population average concept)", "options": ["About 70% manifest the phenotype (population average concept)", "Exactly 70% of offspring inherit the allele", "Severity is always identical", "No counselling is needed"], "lecture": "5.8 Phenotypic Variability", "level": "application"}, {"q": "A de novo dominant mutation in a child with unaffected parents is best explained by:", "a": "New mutation in a parental gamete (or early embryo)", "options": ["New mutation in a parental gamete (or early embryo)", "Obligate recessive inheritance only", "Maternal mitochondrial transmission of nuclear AD traits", "Non-paternity as the only possibility"], "lecture": "5.1 Modes of Inheritance", "level": "application"}], "vsaq": [{"q": "Inheritance pattern needing two mutant alleles for disease?", "a": "Autosomal recessive", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Inheritance pattern where one mutant allele causes disease?", "a": "Autosomal dominant", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Trisomy 21 is also called?", "a": "Down syndrome", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Failure of chromosomes to separate in meiosis?", "a": "Nondisjunction", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Study of genetic effects on drug response?", "a": "Pharmacogenetics", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Brittle bone disease commonly involves which protein?", "a": "Collagen", "lecture": "5.4 Brittle Bones", "level": "recall"}, {"q": "Name a major breast/ovarian cancer susceptibility gene.", "a": ["BRCA1", "BRCA2"], "lecture": "5.6 Cancer Genetics", "level": "recall"}, {"q": "Not all genotype carriers show phenotype: term?", "a": "Incomplete penetrance", "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Same genotype, different severity: term?", "a": "Variable expressivity", "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "Mitochondrial DNA is inherited from which parent?", "a": "Mother", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Extra or missing chromosomes: term?", "a": "Aneuploidy", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Gene-editing system using guide RNA?", "a": "CRISPR", "lecture": "5.9 Emerging Treatments", "level": "recall"}, {"q": "Males express X-linked recessive traits more: why hemizygous?", "a": "One X", "lecture": "5.1 Modes of Inheritance", "level": "understanding"}, {"q": "Tumour suppressor needing two hits typically?", "a": ["Both alleles", "Two alleles"], "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Multifactorial disease involves genes plus?", "a": "Environment", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Karyotyping detects mainly what scale of change?", "a": ["Chromosomal", "Large rearrangements", "Aneuploidy"], "lecture": "5.7 Genetic Testing", "level": "understanding"}, {"q": "Cascade testing screens which group after a familial variant?", "a": "Relatives", "lecture": "5.6 Cancer Genetics", "level": "application"}, {"q": "Earlier onset in successive generations of repeat disease?", "a": "Anticipation", "lecture": "5.8 Phenotypic Variability", "level": "recall"}, {"q": "Related parents: term for shared ancestry mating?", "a": "Consanguinity", "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Chromosome number in typical human somatic cell?", "a": "46", "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "Monosomy X syndrome name?", "a": ["Turner", "Turner syndrome"], "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "XXY syndrome name?", "a": ["Klinefelter", "Klinefelter syndrome"], "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}, {"q": "GWAS stands for genome-wide association?", "a": "Study", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "Enzyme family often mediating drug metabolism?", "a": ["CYP450", "Cytochrome P450", "CYP"], "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "recall"}, {"q": "OI commonly short for osteogenesis?", "a": "Imperfecta", "lecture": "5.4 Brittle Bones", "level": "recall"}, {"q": "Knudson hypothesis involves how many hits for many TSGs?", "a": "Two", "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "Somatic mutations occur in which cells?", "a": ["Body", "Non-germline", "Somatic"], "lecture": "5.6 Cancer Genetics", "level": "recall"}, {"q": "NGS stands for next-generation?", "a": "Sequencing", "lecture": "5.7 Genetic Testing", "level": "recall"}, {"q": "VUS means variant of uncertain?", "a": "Significance", "lecture": "5.7 Genetic Testing", "level": "recall"}, {"q": "One gene, many effects: term?", "a": "Pleiotropy", "lecture": "5.8 Phenotypic Variability", "level": "recall"}, {"q": "Same phenotype, different genes: genetic?", "a": "Heterogeneity", "lecture": "5.8 Phenotypic Variability", "level": "understanding"}, {"q": "ASO therapy often targets which molecule?", "a": ["RNA", "mRNA"], "lecture": "5.9 Emerging Treatments", "level": "recall"}, {"q": "Heritable genome edits affect which lineage?", "a": "Germline", "lecture": "5.9 Emerging Treatments", "level": "understanding"}, {"q": "New mutation not inherited from parents?", "a": ["De novo", "De novo mutation"], "lecture": "5.1 Modes of Inheritance", "level": "recall"}, {"q": "Both chromosome copies from one parent?", "a": ["UPD", "Uniparental disomy"], "lecture": "5.2 Chromosomal Abnormalities", "level": "recall"}], "saq": [{"q": "Distinguish autosomal dominant and autosomal recessive inheritance using recurrence risk ideas for offspring of two carrier parents versus an affected AD parent.", "a": "AD: an affected heterozygote typically has 50% risk of transmitting the allele each child. AR: two carrier parents have 25% risk of an affected child, 50% carriers, 25% non-carriers each pregnancy (assuming complete penetrance).", "lecture": "5.1 Modes of Inheritance", "level": "application"}, {"q": "Explain how meiotic nondisjunction leads to Down syndrome, and why maternal age is a risk factor in many cases.", "a": "Nondisjunction yields gametes with an extra chromosome 21; fertilisation produces trisomy 21. Risk rises with maternal age because meiosis I arrest in oocytes is prolonged, increasing chance of segregation errors.", "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "Why do complex diseases not follow simple Mendelian ratios, and how do GWAS contribute?", "a": "Many loci of small effect plus environment determine risk, so pedigrees lack clear single-gene patterns. GWAS associate SNPs with disease risk across populations, highlighting pathways rather than guaranteeing causation in individuals.", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "inference"}, {"q": "Give an example of a pharmacogenetic interaction and why it matters clinically.", "a": "Example: CYP2C9/VKORC1 variants affect warfarin dose requirement/bleeding risk; TPMT variants affect thiopurine toxicity; HLA-B*5701 and abacavir hypersensitivity. Testing can guide dose or drug choice to improve safety/efficacy.", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "application"}, {"q": "Describe how collagen defects cause brittle bones in osteogenesis imperfecta.", "a": "Type I collagen is critical for bone tensile strength. Qualitative or quantitative collagen defects weaken bone matrix, leading to fractures, bone deformity, and other connective-tissue features depending on type/severity.", "lecture": "5.4 Brittle Bones", "level": "understanding"}, {"q": "Compare oncogenes and tumour suppressor genes in cancer genetics, with inheritance implications for germline predisposition.", "a": "Oncogenes: gain-of-function drivers (often somatic). Tumour suppressors: loss-of-function; germline heterozygous mutation plus somatic second hit explains dominant cancer predisposition pedigrees (Knudson two-hit).", "lecture": "5.6 Cancer Genetics", "level": "understanding"}, {"q": "A healthy balanced translocation carrier asks about reproductive risks. What do you explain?", "a": "Their somatic karyotype is balanced so they are usually well, but meiosis can produce unbalanced gametes. This raises risks of miscarriage or offspring with partial trisomy/monosomy; reproductive options and testing can be discussed.", "lecture": "5.2 Chromosomal Abnormalities", "level": "application"}, {"q": "Define incomplete penetrance and variable expressivity and explain why they complicate genetic counselling.", "a": "Incomplete penetrance: genotype without phenotype in some individuals. Variable expressivity: differing severity/features among those affected. Counselling must avoid absolute predictions and discuss ranges of outcomes and surveillance.", "lecture": "5.8 Phenotypic Variability", "level": "inference"}, {"q": "Outline ethical issues raised by predictive genetic testing for late-onset disease.", "a": "Issues include autonomy, informed consent, psychological impact, privacy, possible insurance/employment discrimination, testing of minors, and implications for relatives who may not wish to know.", "lecture": "5.7 Genetic Testing", "level": "inference"}, {"q": "Describe the promise and risks of gene therapy / genome editing for monogenic disease.", "a": "Promise: durable correction of the underlying defect. Risks: immune reactions to vectors, insertional mutagenesis, off-target edits, incomplete efficacy, and ethical concerns about germline editing.", "lecture": "5.9 Emerging Treatments", "level": "understanding"}, {"q": "Why might two siblings with the same pathogenic variant show different severity?", "a": "Modifier genes, environmental factors, stochastic effects, mosaicism, allelic variation, and epigenetic influences can alter expressivity even with the same primary variant.", "lecture": "5.8 Phenotypic Variability", "level": "inference"}, {"q": "Explain maternal inheritance of mitochondrial disorders and heteroplasmy.", "a": "mtDNA is transmitted through the oocyte. Cells can contain mixed mutant/wild-type mtDNA (heteroplasmy); the proportion influences phenotype severity and tissue distribution, producing variable expression.", "lecture": "5.1 Modes of Inheritance", "level": "understanding"}, {"q": "Explain why X-inactivation can modify expression of X-linked disorders in females.", "a": "One X is randomly inactivated in each cell (lyonisation), producing mosaicism. Skewed inactivation can worsen or ameliorate phenotype in female carriers of X-linked mutations.", "lecture": "5.1 Modes of Inheritance", "level": "inference"}, {"q": "Compare numerical and structural chromosomal abnormalities with one example each.", "a": "Numerical: aneuploidy such as trisomy 21. Structural: deletions, duplications, inversions, translocations (e.g. Robertsonian translocation) that rearrange chromosome content.", "lecture": "5.2 Chromosomal Abnormalities", "level": "understanding"}, {"q": "How can a balanced translocation be associated with recurrent miscarriage?", "a": "Segregation can produce unbalanced gametes. Conceptuses with partial trisomy/monosomy may miscarry, while the balanced carrier parent remains healthy.", "lecture": "5.2 Chromosomal Abnormalities", "level": "application"}, {"q": "Explain the difference between a monogenic and a polygenic contribution to disease risk.", "a": "Monogenic: a single gene variant has large effect and Mendelian pattern. Polygenic: many variants of small effect combine (often with environment) to influence risk without clear single-gene segregation.", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "understanding"}, {"q": "A patient is a poor metaboliser for a CYP enzyme that inactivates a drug. What dosing principle follows?", "a": "Expect higher exposure and toxicity risk at standard doses; consider lower dose, alternative drug, or guided dosing per evidence, and monitor closely.", "lecture": "5.3 Complex Disease and Pharmacogenetics", "level": "application"}, {"q": "Why do qualitative collagen mutations sometimes cause more severe OI than simple null alleles?", "a": "Abnormal collagen chains can poison the triple helix (dominant-negative), disrupting many molecules. A null allele may only reduce quantity, sometimes yielding milder disease.", "lecture": "5.4 Brittle Bones", "level": "inference"}, {"q": "Distinguish germline and somatic mutations in cancer risk counselling.", "a": "Germline variants are in all cells and heritable, raising lifetime cancer risk and family implications. Somatic mutations arise in the tumour and are generally not inherited by offspring.", "lecture": "5.6 Cancer Genetics", "level": "application"}, {"q": "Explain why finding a VUS should not usually drive irreversible clinical decisions alone.", "a": "VUS lacks proven pathogenicity; acting as if pathogenic risks unnecessary surgery/anxiety, while dismissing it as benign may be wrong. Reclassification over time and family studies may help; manage by phenotype and guidelines.", "lecture": "5.7 Genetic Testing", "level": "application"}, {"q": "How do modifier genes help explain variable expressivity?", "a": "Other loci alter the impact of a primary pathogenic variant through parallel pathways, compensation, or environmental interaction, changing severity among individuals with the same primary genotype.", "lecture": "5.8 Phenotypic Variability", "level": "inference"}, {"q": "Outline mechanisms of antisense oligonucleotide drugs and one safety consideration.", "a": "ASOs bind RNA to alter splicing or promote degradation/block translation. Considerations include off-target effects, delivery challenges, immune reactions, and need for repeated dosing.", "lecture": "5.9 Emerging Treatments", "level": "understanding"}, {"q": "Discuss why somatic CRISPR editing for disease differs ethically from germline editing.", "a": "Somatic edits aim to treat an individual and are not inherited. Germline edits affect descendants, raising consent, equity, unintended heritable harms, and societal governance issues.", "lecture": "5.9 Emerging Treatments", "level": "inference"}, {"q": "A couple has a child with a rare AR disease; the next pregnancy risk is often quoted as 25%. State assumptions behind that figure.", "a": "Assumes both parents are carriers, Mendelian AR inheritance, full penetrance, correct diagnosis, and no unusual mechanisms (e.g. non-paternity, de novo, uniparental disomy). Empiric risks may be refined with testing.", "lecture": "5.1 Modes of Inheritance", "level": "application"}, {"q": "Explain how chromosomal microarray differs from a standard karyotype in what it detects.", "a": "Karyotype sees large chromosomal changes and rearrangements at low resolution. Microarrays detect smaller copy-number variants (deletions/duplications) but may miss balanced rearrangements without copy-number change.", "lecture": "5.7 Genetic Testing", "level": "understanding"}]}}};
